sql.where:
MO.MGMT_OFC_NO = #{mgmtOfcNo}
AND AC.APT_CMPLEX_NM = #{complexName}
AND AD.DONG_NO LIKE '%' || #{dong} || '%'
AND AD.HO LIKE '%' || #{ho} || '%'
AND HH.HEAD_YN = 'Y'
AND HH.HEAD_YN = 'N'
AND HH.INOUT_CD = #{moveStatus}
AND ( M.USER_NO LIKE '%' || #{keyword} || '%' OR M.USER_NM LIKE '%' || #{keyword} || '%' OR M.USER_TELNO LIKE '%' || #{keyword} || '%' OR M.USER_EML LIKE '%' || #{keyword} || '%' OR AD.HO LIKE '%' || #{keyword} || '%' OR AD.DONG_NO LIKE '%' || #{keyword} || '%' )
AND HH.MOVE_IN_DT >= TO_DATE(#{moveInStart}, 'YYYY-MM-DD')
AND HH.MOVE_IN_DT < TO_DATE(#{moveInEnd}, 'YYYY-MM-DD') + 1
